// Logger class for logging significant actions
class Logger {
public:
    static void log(const std::string& message) {
        time_t now = time(0);
        char* dt = ctime(&now);
        std::cout << "[" << dt << "] " << message << std::endl;
    }
};

// Base Account class
class Account {
protected:
    std::string accountNumber;
    double balance;
    std::string accountHolder;

public:
    Account(const std::string& accNum, const std::string& holder, double initialBalance)
        : accountNumber(accNum), accountHolder(holder), balance(initialBalance) {}

    virtual ~Account() {}

    virtual double calculateInterest() const = 0;

    void deposit(double amount) {
        if (amount <= 0) {
            Logger::log("Deposit failed: Invalid amount for account " + accountNumber);
            throw std::invalid_argument("Amount must be positive");
        }
        balance += amount;
        Logger::log("Deposited $" + std::to_string(amount) + " to account " + accountNumber);
    }

    void withdraw(double amount) {
        if (amount <= 0) {
            Logger::log("Withdrawal failed: Invalid amount for account " + accountNumber);
            throw std::invalid_argument("Amount must be positive");
        }
        if (amount > balance) {
            Logger::log("Withdrawal failed: Insufficient balance in account " + accountNumber);
            throw std::runtime_error("Insufficient balance");
        }
        balance -= amount;
        Logger::log("Withdrew $" + std::to_string(amount) + " from account " + accountNumber);
    }

    double getBalance() const {
        return balance;
    }

    std::string getAccountNumber() const {
        return accountNumber;
    }

    std::string getAccountHolder() const {
        return accountHolder;
    }
};

// Savings Account
class SavingsAccount : public Account {
private:
    double interestRate;

public:
    SavingsAccount(const std::string& accNum, const std::string& holder, double initialBalance, double rate)
        : Account(accNum, holder, initialBalance), interestRate(rate) {}

    double calculateInterest() const override {
        return balance * interestRate / 100;
    }
};

