// Bank class to manage accounts
class Bank {
private:
    std::stack<Account*> accounts;

public:
    ~Bank() {
        while (!accounts.empty()) {
            delete accounts.top();
            accounts.pop();
        }
    }

    void addAccount(Account* account) {
        if (accounts.size() >= 300) {
            Logger::log("Account addition failed: Maximum capacity reached");
            throw std::runtime_error("Maximum account capacity reached");
        }
        if (account == nullptr) {
            Logger::log("Account addition failed: Null account");
            throw std::invalid_argument("Account cannot be null");
        }
        accounts.push(account);
        Logger::log("Added account " + account->getAccountNumber() + " to the bank");
    }

    Account* getAccount(const std::string& accNum) {
        std::stack<Account*> temp;
        Account* found = nullptr;

        while (!accounts.empty()) {
            Account* acc = accounts.top();
            accounts.pop();
            if (acc->getAccountNumber() == accNum) {
                found = acc;
                break;
            }
            temp.push(acc);
        }

        // Restore the stack
        while (!temp.empty()) {
            accounts.push(temp.top());
            temp.pop();
        }

        if (found == nullptr) {
            Logger::log("Account retrieval failed: Account " + accNum + " not found");
        }
        return found;
    }
};

int main() {
    Bank bank;

    try {
        SavingsAccount* savings = new SavingsAccount("SA001", "John Doe", 1000, 2.5);
        CheckingAccount* checking = new CheckingAccount("CA001", "Jane Doe", 2000, 1.5);
        JointAccount* joint = new JointAccount("JA001", "Alice", "Bob", 3000, 1.0);

        bank.addAccount(savings);
        bank.addAccount(checking);
        bank.addAccount(joint);

        Account* acc = bank.getAccount("SA001");
        if (acc != nullptr) {
            acc->deposit(500);
            acc->withdraw(200);
            std::cout << "Interest: $" << acc->calculateInterest() << std::endl;
        }

    } catch (const std::exception& e) {
        Logger::log("Error: " + std::string(e.what()));
    }

    return 0;
}
