package main

import (
	"fmt"
	"sync"
	"time"
)

type Message struct {
	User    string
	Content string
	Time    time.Time
}

type ChatServer struct {
	messageChan chan Message
	mu          sync.Mutex
}

func NewChatServer(bufferSize int) *ChatServer {
	return &ChatServer{
		messageChan: make(chan Message, bufferSize),
	}
}

func (cs *ChatServer) AddMessage(user, content string) {
	msg := Message{
		User:    user,
		Content: content,
		Time:    time.Now(),
	}

	select {
	case cs.messageChan <- msg:
		// Message added successfully
	default:
		// Channel is full, remove oldest message and add new one
		<-cs.messageChan
		cs.messageChan <- msg
	}
}

func (cs *ChatServer) ProcessMessages() {
	for msg := range cs.messageChan {
		cs.mu.Lock()
		fmt.Printf("[%s] %s: %s\n", msg.Time.Format("15:04:05"), msg.User, msg.Content)
		cs.mu.Unlock()
	}
}

func main() {
	chat := NewChatServer(200)
	go chat.ProcessMessages()

	// Simulate multiple users sending messages
	users := []string{"Alice", "Bob", "Charlie"}
	var wg sync.WaitGroup

	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(idx int) {
			defer wg.Done()
			user := users[idx%len(users)]
			chat.AddMessage(user, fmt.Sprintf("Message %d from %s", idx, user))
		}(i)
	}

	wg.Wait()
	time.Sleep(1 * time.Second) // Allow time for processing
}
