import collections
import math

def evaluate_expression(expr, cache=collections.defaultdict(lambda: None), max_cache_size=1000):
    if cache[expr] is not None:
        return cache[expr]
    try:
        result = eval(expr, {'__builtins__': None, 'math': math}, {})
        if len(cache) >= max_cache_size:
            cache.pop(next(iter(cache)))
        cache[expr] = result
        return result
    except:
        raise ValueError("Invalid expression or unsupported operation")
