import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;
import java.time.Instant;

public class SessionMonitor {
    private static final int MAX_SESSIONS = 500;
    private static final long INACTIVITY_LIMIT = 30 * 60 * 1000; // 30 minutes in milliseconds
    private final ConcurrentHashMap<String, Long> activeSessions = new ConcurrentHashMap<>();

    public synchronized boolean addSession(String sessionId) {
        cleanupInactiveSessions();
        if (activeSessions.size() >= MAX_SESSIONS) {
            return false;
        }
        activeSessions.put(sessionId, Instant.now().toEpochMilli());
        return true;
    }

    public void updateSessionActivity(String sessionId) {
        if (activeSessions.containsKey(sessionId)) {
            activeSessions.put(sessionId, Instant.now().toEpochMilli());
        }
    }

    public void removeSession(String sessionId) {
        activeSessions.remove(sessionId);
    }

    private void cleanupInactiveSessions() {
        long currentTime = Instant.now().toEpochMilli();
        activeSessions.entrySet().removeIf(entry -> 
            (currentTime - entry.getValue()) > INACTIVITY_LIMIT
        );
    }

    public int getActiveSessionCount() {
        return activeSessions.size();
    }
}
