import java.util.*;

public class LinkedListMerger {

    public static LinkedList<Integer> mergeSortedLinkedLists(List<LinkedList<Integer>> lists) {
        if (lists == null || lists.isEmpty()) {
            return new LinkedList<>();
        }

        PriorityQueue<Node> minHeap = new PriorityQueue<>(Comparator.comparingInt(node -> node.value));

        // Add the first node of each non-empty list to the min-heap
        for (LinkedList<Integer> list : lists) {
            if (list != null && !list.isEmpty()) {
                minHeap.offer(new Node(list.removeFirst(), list));
            }
        }

        LinkedList<Integer> mergedList = new LinkedList<>();
        while (!minHeap.isEmpty() && mergedList.size() < 10000) {
            Node minNode = minHeap.poll();
            mergedList.add(minNode.value);

            if (!minNode.list.isEmpty()) {
                minHeap.offer(new Node(minNode.list.removeFirst(), minNode.list));
            }
        }

        return mergedList;
    }

    private static class Node {
        int value;
        LinkedList<Integer> list;

        Node(int value, LinkedList<Integer> list) {
            this.value = value;
            this.list = list;
        }
    }
}
