use std::collections::HashSet;

fn max_non_adjacent_sum(nums: &[i32]) -> i32 {
    let mut dp = vec![0; nums.len()];
    let mut sum_set: HashSet<i32> = HashSet::with_capacity(1500);

    if nums.is_empty() {
        return 0;
    }

    dp[0] = nums[0];
    sum_set.insert(dp[0]);

    if nums.len() == 1 {
        return dp[0];
    }

    dp[1] = std::cmp::max(nums[0], nums[1]);
    sum_set.insert(dp[1]);

    for i in 2..nums.len() {
        let current_sum = nums[i] + dp[i - 2];
        dp[i] = std::cmp::max(current_sum, dp[i - 1]);

        if sum_set.len() < 1500 {
            sum_set.insert(dp[i]);
        }
    }

    dp[nums.len() - 1]
}

fn main() {
    let nums = vec![2, 4, 6, 2, 5];
    println!("{}", max_non_adjacent_sum(&nums));
}
