#include <iostream>
#include <unordered_map>
#include <vector>
#include <stdexcept>
#include <string>

class Flight {
public:
    std::string flightNumber;
    int totalSeats;
    int bookedSeats;

    Flight(const std::string& number, int seats) 
        : flightNumber(number), totalSeats(seats), bookedSeats(0) {}

    bool reserveSeats(int seats) {
        if (bookedSeats + seats > totalSeats) {
            return false;
        }
        bookedSeats += seats;
        return true;
    }

    bool cancelSeats(int seats) {
        if (bookedSeats - seats < 0) {
            return false;
        }
        bookedSeats -= seats;
        return true;
    }

    int availableSeats() const {
        return totalSeats - bookedSeats;
    }
};

class Airline {
private:
    std::vector<Flight> flights;
    const int MAX_FLIGHTS = 300;

public:
    bool addFlight(const std::string& flightNumber, int totalSeats) {
        if (flights.size() >= MAX_FLIGHTS) {
            return false;
        }
        flights.emplace_back(flightNumber, totalSeats);
        return true;
    }

    Flight* getFlight(const std::string& flightNumber) {
        for (auto& flight : flights) {
            if (flight.flightNumber == flightNumber) {
                return &flight;
            }
        }
        return nullptr;
    }

    const std::vector<Flight>& getFlights() const {
        return flights;
    }
};

class FlightReservationSystem {
private:
    std::unordered_map<std::string, Airline> airlines;

public:
    void addAirline(const std::string& name) {
        airlines.emplace(name, Airline());
    }

    bool addFlight(const std::string& airlineName, const std::string& flightNumber, int totalSeats) {
        auto it = airlines.find(airlineName);
        if (it == airlines.end()) {
            return false;
        }
        return it->second.addFlight(flightNumber, totalSeats);
    }

    bool reserveSeats(const std::string& airlineName, const std::string& flightNumber, int seats) {
        auto it = airlines.find(airlineName);
        if (it == airlines.end()) {
            throw std::invalid_argument("Airline not found.");
        }
        Flight* flight = it->second.getFlight(flightNumber);
        if (!flight) {
            throw std::invalid_argument("Flight not found.");
        }
        if (!flight->reserveSeats(seats)) {
            throw std::runtime_error("Not enough seats available.");
        }
        return true;
    }

    bool cancelSeats(const std::string& airlineName, const std::string& flightNumber, int seats) {
        auto it = airlines.find(airlineName);
        if (it == airlines.end()) {
            throw std::invalid_argument("Airline not found.");
        }
        Flight* flight = it->second.getFlight(flightNumber);
        if (!flight) {
            throw std::invalid_argument("Flight not found.");
        }
        if (!flight->cancelSeats(seats)) {
            throw std::runtime_error("Invalid cancellation request.");
        }
        return true;
    }

    int checkAvailability(const std::string& airlineName, const std::string& flightNumber) {
        auto it = airlines.find(airlineName);
        if (it == airlines.end()) {
            throw std::invalid_argument("Airline not found.");
        }
        Flight* flight = it->second.getFlight(flightNumber);
        if (!flight) {
            throw std::invalid_argument("Flight not found.");
        }
        return flight->availableSeats();
    }
};

int main() {
    FlightReservationSystem system;
    system.addAirline("Delta");
    system.addFlight("Delta", "DL101", 150);

    try {
        system.reserveSeats("Delta", "DL101", 5);
        std::cout << "Seats reserved. Available seats: " << system.checkAvailability("Delta", "DL101") << std::endl;
        system.cancelSeats("Delta", "DL101", 2);
        std::cout << "Seats canceled. Available seats: " << system.checkAvailability("Delta", "DL101") << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
