struct Task {
    description: String,
    completed: bool,
}

fn task_manager_cli() {
    let mut tasks: VecDeque<Task> = VecDeque::with_capacity(50);

    loop {
        println!("Task Manager CLI");
        println!("1. Add Task");
        println!("2. Remove Task");
        println!("3. View Tasks");
        println!("4. Exit");

        let mut choice = String::new();
        io::stdin().read_line(&mut choice).expect("Failed to read line");
        let choice: u32 = match choice.trim().parse() {
            Ok(num) => num,
            Err(_) => continue,
        };

        match choice {
            1 => {
                if tasks.len() >= 50 {
                    println!("Task limit reached (50 tasks max).");
                    continue;
                }
                println!("Enter task description:");
                let mut description = String::new();
                io::stdin().read_line(&mut description).expect("Failed to read line");
                tasks.push_back(Task {
                    description: description.trim().to_string(),
                    completed: false,
                });
                println!("Task added.");
            },
            2 => {
                if tasks.is_empty() {
                    println!("No tasks to remove.");
                    continue;
                }
                println!("Enter task index to remove:");
                let mut index = String::new();
                io::stdin().read_line(&mut index).expect("Failed to read line");
                let index: usize = match index.trim().parse() {
                    Ok(num) => num,
                    Err(_) => continue,
                };
                if index >= tasks.len() {
                    println!("Invalid index.");
                    continue;
                }
                tasks.remove(index);
                println!("Task removed.");
            },
            3 => {
                if tasks.is_empty() {
                    println!("No tasks to display.");
                    continue;
                }
                for (i, task) in tasks.iter().enumerate() {
                    println!("{}. [{}] {}", i, if task.completed { "X" } else { " " }, task.description);
                }
            },
            4 => break,
            _ => println!("Invalid choice."),
        }
    }
}
