import java.util.ArrayList;
import java.io.File;

public class FileMetadataCache {
    private ArrayList<FileMetadata> cache;

    public FileMetadataCache() {
        this.cache = new ArrayList<>();
    }

    public static class FileMetadata {
        private String filename;
        private long lastModified;
        private long fileSize;

        public FileMetadata(String filename, long lastModified, long fileSize) {
            this.filename = filename;
            this.lastModified = lastModified;
            this.fileSize = fileSize;
        }

        public String getFilename() {
            return filename;
        }

        public long getLastModified() {
            return lastModified;
        }

        public long getFileSize() {
            return fileSize;
        }
    }

    public void addFile(String filename) {
        File file = new File(filename);
        if (file.exists()) {
            FileMetadata metadata = new FileMetadata(
                filename,
                file.lastModified(),
                file.length()
            );
            cache.add(metadata);
        }
    }

    public FileMetadata getFileMetadata(String filename) {
        for (FileMetadata metadata : cache) {
            if (metadata.getFilename().equals(filename)) {
                return metadata;
            }
        }
        return null;
    }

    public boolean removeFile(String filename) {
        for (int i = 0; i < cache.size(); i++) {
            if (cache.get(i).getFilename().equals(filename)) {
                cache.remove(i);
                return true;
            }
        }
        return false;
    }
}
