	}
}

func (tb *TemperatureBuffer) Add(temp float64) error {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	if math.IsNaN(temp) {
		return errors.New("invalid temperature value: NaN")
	}

	tb.buffer.Value = temp
	tb.buffer = tb.buffer.Next()

	if tb.count < tb.size {
		tb.count++
	}

	return nil
}

func (tb *TemperatureBuffer) MovingAverage() (float64, error) {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	if tb.count == 0 {
		return 0, errors.New("buffer is empty")
	}

	sum := 0.0
	n := 0
	tb.buffer.Do(func(val interface{}) {
		if val != nil {
			sum += val.(float64)
			n++
		}
	})

	return sum / float64(n), nil
}

func main() {
	logger := log.New(os.Stdout, "TEMPERATURE_PROCESSOR: ", log.LstdFlags|log.Lshortfile)

	buffer := NewTemperatureBuffer(1000)
	temps := []float64{20.5, 21.0, 22.3, 23.7, 24.1} // Example data

	for _, temp := range temps {
		if err := buffer.Add(temp); err != nil {
			logger.Printf("ERROR: %v", err)
			continue
		}
		logger.Printf("DEBUG: Added temperature %.2f to buffer", temp)
	}

	avg, err := buffer.MovingAverage()
	if err != nil {
		logger.Printf("ERROR: %v", err)
		return
	}

	logger.Printf("INFO: Moving average: %.2f", avg)
}
