    double price;
    Genre genre;
    int quantity;
};

class BookstoreCheckout {
private:
    map<int, Product> productCatalog; // Key: Product ID, Value: Product details
    const int MAX_ENTRIES = 500;

    // Custom sorting comparator for price
    static bool compareByPrice(const pair<int, Product>& a, const pair<int, Product>& b) {
        return a.second.price < b.second.price;
    }

    // Custom sorting comparator for genre
    static bool compareByGenre(const pair<int, Product>& a, const pair<int, Product>& b) {
        return a.second.genre < b.second.genre;
    }

public:
    void addProduct(int id, const Product& product) {
        if (productCatalog.size() < MAX_ENTRIES) {
            productCatalog[id] = product;
        } else {
            cerr << "Catalog is full (max 500 entries)." << endl;
        }
    }

    void applyDiscount(int id, double discountPercent) {
        if (productCatalog.find(id) != productCatalog.end()) {
            productCatalog[id].price *= (1 - discountPercent / 100);
        }
    }

    double calculateTotal(const map<int, int>& cart) {
        double total = 0.0;
        for (const auto& item : cart) {
            if (productCatalog.find(item.first) != productCatalog.end()) {
                total += productCatalog[item.first].price * item.second;
            }
        }
        return total;
    }

    void sortCatalogByPrice() {
        vector<pair<int, Product>> sortedProducts(productCatalog.begin(), productCatalog.end());
        sort(sortedProducts.begin(), sortedProducts.end(), compareByPrice);
        productCatalog.clear();
        for (const auto& item : sortedProducts) {
            productCatalog[item.first] = item.second;
        }
    }

    void sortCatalogByGenre() {
        vector<pair<int, Product>> sortedProducts(productCatalog.begin(), productCatalog.end());
        sort(sortedProducts.begin(), sortedProducts.end(), compareByGenre);
        productCatalog.clear();
        for (const auto& item : sortedProducts) {
            productCatalog[item.first] = item.second;
        }
    }

    void displayCatalog() {
        for (const auto& item : productCatalog) {
            cout << "ID: " << item.first << ", Name: " << item.second.name 
                 << ", Price: $" << item.second.price << ", Genre: " << static_cast<int>(item.second.genre) 
                 << ", Quantity: " << item.second.quantity << endl;
        }
    }
};

int main() {
    BookstoreCheckout checkout;
    // Example usage:
    Product p1 = {"Book1", 19.99, Genre::FICTION, 10};
    Product p2 = {"Book2", 12.99, Genre::SCI_FI, 5};
    checkout.addProduct(1, p1);
    checkout.addProduct(2, p2);

    map<int, int> cart = {{1, 2}, {2, 1}};
    cout << "Total: $" << checkout.calculateTotal(cart) << endl;

    checkout.sortCatalogByPrice();
    checkout.displayCatalog();

    return 0;
}
