        if (newName.empty()) {
            throw std::invalid_argument("Name cannot be empty");
        }
        name = newName;
    }

    void setAge(int newAge) {
        if (newAge < 0) {
            throw std::invalid_argument("Age cannot be negative");
        }
        age = newAge;
    }
};

// Custom comparison for age (ascending)
bool compareByAge(const Employee& a, const Employee& b) {
    return a.getAge() < b.getAge();
}

// Custom comparison for name (ascending, case-sensitive)
bool compareByName(const Employee& a, const Employee& b) {
    return a.getName() < b.getName();
}

// Stable sort by age, then by name
void stableSortEmployees(std::deque<Employee>& employees) {
    if (employees.empty()) {
        return;
    }

    if (employees.size() > 800) {
        throw std::overflow_error("Employee deque exceeds capacity of 800");
    }

    // First sort by name (stable)
    std::stable_sort(employees.begin(), employees.end(), compareByName);
    // Then sort by age (stable)
    std::stable_sort(employees.begin(), employees.end(), compareByAge);
}

int main() {
    try {
        std::deque<Employee> employees;

        // Example usage
        employees.emplace_back("John Doe", 30);
        employees.emplace_back("Alice Smith", 25);
        employees.emplace_back("Bob Johnson", 30);
        employees.emplace_back("Alice Smith", 20);

        stableSortEmployees(employees);

        // Print sorted employees
        for (const auto& emp : employees) {
            std::cout << "Name: " << emp.getName() << ", Age: " << emp.getAge() << std::endl;
        }

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
