use std::collections::LinkedList;
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug, Clone)]
struct Message {
    id: u64,
    timestamp: u64,
    content: String,
}

#[derive(Debug)]
enum QueueError {
    Overflow,
    NotFound,
    InvalidOperation,
}

struct MessageQueue {
    messages: LinkedList<Message>,
    max_size: usize,
}

impl MessageQueue {
    fn new(max_size: usize) -> Self {
        MessageQueue {
            messages: LinkedList::new(),
            max_size,
        }
    }

    fn enqueue(&mut self, content: String) -> Result<u64, QueueError> {
        if self.messages.len() >= self.max_size {
            return Err(QueueError::Overflow);
        }

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();
        let id = timestamp + rand::random::<u64>() % 1000;

        let message = Message {
            id,
            timestamp,
            content,
        };

        self.messages.push_back(message);
        Ok(id)
    }

    fn dequeue(&mut self) -> Result<Message, QueueError> {
        if self.messages.is_empty() {
            return Err(QueueError::InvalidOperation);
        }
        Ok(self.messages.pop_front().unwrap())
    }

    fn lookup(&self, id: u64) -> Result<Message, QueueError> {
        self.messages
            .iter()
            .find(|msg| msg.id == id)
            .cloned()
            .ok_or(QueueError::NotFound)
    }
}

fn main() {
    let mut queue = MessageQueue::new(500);
    match queue.enqueue("Test message".to_string()) {
        Ok(id) => println!("Enqueued message with ID: {}", id),
        Err(e) => println!("Error: {:?}", e),
    }
}
