class CinemaReservationSystem {
private:
    std::set<int> bookedSeats;
    std::mutex mtx;
    const int MAX_SEATS = 10000;

public:
    bool reserveSeat(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        if (bookedSeats.size() >= MAX_SEATS) {
            throw std::runtime_error("Overbooking not allowed. Maximum capacity reached.");
        }
        if (seatNumber < 1 || seatNumber > MAX_SEATS) {
            throw std::out_of_range("Invalid seat number.");
        }
        auto result = bookedSeats.insert(seatNumber);
        return result.second;
    }

    bool cancelReservation(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        if (seatNumber < 1 || seatNumber > MAX_SEATS) {
            throw std::out_of_range("Invalid seat number.");
        }
        return bookedSeats.erase(seatNumber) > 0;
    }

    bool isSeatAvailable(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        if (seatNumber < 1 || seatNumber > MAX_SEATS) {
            throw std::out_of_range("Invalid seat number.");
        }
        return bookedSeats.find(seatNumber) == bookedSeats.end();
    }

    int getAvailableSeatsCount() {
        std::lock_guard<std::mutex> lock(mtx);
        return MAX_SEATS - bookedSeats.size();
    }
};

