import java.util.TreeSet;
import java.util.logging.Logger;
import java.util.logging.Level;

class Task implements Comparable<Task> {
    private final int id;
    private final int priority;

    public Task(int id, int priority) {
        this.id = id;
        this.priority = priority;
    }

    public int getId() {
        return id;
    }

    public int getPriority() {
        return priority;
    }

    @Override
    public int compareTo(Task other) {
        if (this.priority != other.priority) {
            return Integer.compare(this.priority, other.priority);
        } else {
            return Integer.compare(this.id, other.id);
        }
    }

    @Override
    public String toString() {
        return "Task{id=" + id + ", priority=" + priority + "}";
    }
}

public class TaskScheduler {
    private static final Logger logger = Logger.getLogger(TaskScheduler.class.getName());
    private static final int MAX_TASKS = 200;
    private final TreeSet<Task> tasks = new TreeSet<>();

    public void addTask(Task task) throws IllegalStateException {
        if (tasks.size() >= MAX_TASKS) {
            logger.log(Level.SEVERE, "Cannot add task " + task.getId() + ": TreeSet is full.");
            throw new IllegalStateException("TreeSet is full. Cannot add more tasks.");
        }
        tasks.add(task);
        logger.log(Level.INFO, "Added task: " + task);
    }

    public void removeTask(Task task) throws IllegalStateException {
        if (tasks.isEmpty()) {
            logger.log(Level.SEVERE, "Cannot remove task " + task.getId() + ": TreeSet is empty.");
            throw new IllegalStateException("TreeSet is empty. Cannot remove tasks.");
        }
        if (tasks.remove(task)) {
            logger.log(Level.INFO, "Removed task: " + task);
        } else {
            logger.log(Level.WARNING, "Task " + task.getId() + " not found in TreeSet.");
        }
    }

    public Task fetchHighestPriorityTask() throws IllegalStateException {
        if (tasks.isEmpty()) {
            logger.log(Level.SEVERE, "Cannot fetch task: TreeSet is empty.");
            throw new IllegalStateException("TreeSet is empty. Cannot fetch tasks.");
        }
        Task task = tasks.last();
        logger.log(Level.INFO, "Fetched highest priority task: " + task);
        return task;
    }

    public Task fetchLowestPriorityTask() throws IllegalStateException {
        if (tasks.isEmpty()) {
            logger.log(Level.SEVERE, "Cannot fetch task: TreeSet is empty.");
            throw new IllegalStateException("TreeSet is empty. Cannot fetch tasks.");
        }
        Task task = tasks.first();
        logger.log(Level.INFO, "Fetched lowest priority task: " + task);
        return task;
    }
}
