using namespace std;

class InventoryItem {
public:
    string name;
    int urgency; // Higher value means higher urgency
    int quantity;

    InventoryItem(string n, int u, int q) : name(n), urgency(u), quantity(q) {}

    // Overload the < operator to prioritize higher urgency
    bool operator<(const InventoryItem& other) const {
        return urgency < other.urgency;
    }
};

class InventorySystem {
private:
    priority_queue<InventoryItem> items;
    const int MAX_ITEMS = 500;

public:
    void addItem(const string& name, int urgency, int quantity) {
        if (items.size() >= MAX_ITEMS) {
            throw runtime_error("Inventory is full (max 500 items).");
        }
        if (urgency < 0 || quantity <= 0) {
            throw invalid_argument("Urgency must be >= 0 and quantity must be > 0.");
        }
        items.push(InventoryItem(name, urgency, quantity));
    }

    InventoryItem removeHighestPriorityItem() {
        if (items.empty()) {
            throw runtime_error("Inventory is empty.");
        }
        InventoryItem item = items.top();
        items.pop();
        return item;
    }

    InventoryItem peekHighestPriorityItem() {
        if (items.empty()) {
            throw runtime_error("Inventory is empty.");
        }
        return items.top();
    }

    bool isEmpty() const {
        return items.empty();
    }

    int size() const {
        return items.size();
    }
};

int main() {
    InventorySystem inventory;

    try {
        inventory.addItem("Laptop", 3, 10);
        inventory.addItem("Smartphone", 5, 20);
        inventory.addItem("Headphones", 2, 15);

