use smallvec::SmallVec;

#[derive(Debug)]
struct Task {
    id: u32,
    priority: u32,
    description: String,
}

struct PriorityQueue {
    tasks: SmallVec<[Task; 200]>,
}

impl PriorityQueue {
    fn new() -> Self {
        PriorityQueue {
            tasks: SmallVec::new(),
        }
    }

    fn add_task(&mut self, id: u32, priority: u32, description: String) -> Result<(), String> {
        if self.tasks.len() >= 200 {
            return Err("Priority queue overflow: Cannot exceed 200 tasks".to_string());
        }
        let task = Task { id, priority, description };
        self.tasks.push(task);
        self.tasks.sort_by(|a, b| b.priority.cmp(&a.priority));
        Ok(())
    }

    fn update_priority(&mut self, id: u32, new_priority: u32) -> Result<(), String> {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == id) {
            task.priority = new_priority;
            self.tasks.sort_by(|a, b| b.priority.cmp(&a.priority));
            Ok(())
        } else {
            Err("Task not found".to_string())
        }
    }

    fn remove_task(&mut self, id: u32) -> Result<(), String> {
        if let Some(pos) = self.tasks.iter().position(|t| t.id == id) {
            self.tasks.remove(pos);
            Ok(())
        } else {
            Err("Task not found".to_string())
        }
    }
}
