```python
import queue

def floyd_warshall(graph):
    nodes = sorted(graph.keys())
    num_nodes = len(nodes)
    node_index = {node: idx for idx, node in enumerate(nodes)}

    # Initialize distance matrix
    dist = [[float('inf')] * num_nodes for _ in range(num_nodes)]
    for i in range(num_nodes):
        dist[i][i] = 0
    for u in graph:
        for v, weight in graph[u].items():
            dist[node_index[u]][node_index[v]] = weight

    # Initialize queue for node pairs
    q = queue.Queue(maxsize=1000)

    # Enqueue all possible node pairs (i, j, k)
    for k in range(num_nodes):
        for i in range(num_nodes):
            for j in range(num_nodes):
                if q.full():
                    q.get()  # Remove oldest item if queue is full
                q.put((i, j, k))

    # Process node pairs from the queue
    while not q.empty():
        i, j, k = q.get()
        if dist[i][k] + dist[k][j] < dist[i][j]:
            dist[i][j] = dist[i][k] + dist[k][j]

    # Convert back to node identifiers
    result = {}
    for i in range(num_nodes):
        result[nodes[i]] = {}
        for j in range(num_nodes):
            result[nodes[i]][nodes[j]] = dist[i][j]

    return result
