use std::collections::BTreeMap;

struct MedianFinder {
    counts: BTreeMap<i32, usize>,
    total: usize,
}

impl MedianFinder {
    fn new() -> Self {
        MedianFinder {
            counts: BTreeMap::new(),
            total: 0,
        }
    }

    fn add_num(&mut self, num: i32) {
        *self.counts.entry(num).or_insert(0) += 1;
        self.total += 1;
    }

    fn find_median(&self) -> f64 {
        if self.total == 0 {
            return 0.0;
        }

        let mut count = 0;
        let target = if self.total % 2 == 1 {
            (self.total / 2) + 1
        } else {
            self.total / 2
        };

        let mut prev_num = 0;
        let mut found = false;

        for (&num, &cnt) in self.counts.iter() {
            count += cnt;
            if count >= target {
                if self.total % 2 == 1 {
                    return num as f64;
                } else {
                    if found {
                        return (prev_num + num) as f64 / 2.0;
                    } else if count > target {
                        return num as f64;
                    } else {
                        prev_num = num;
                        found = true;
                    }
                }
            } else {
                prev_num = num;
            }
        }

        prev_num as f64
    }
}

fn main() {
    let mut finder = MedianFinder::new();
    finder.add_num(1);
    finder.add_num(2);
    println!("Median: {}", finder.find_median());
    finder.add_num(3);
    println!("Median: {}", finder.find_median());
}
