import threading
import queue
import time
import random

class LogProcessor:
    def __init__(self, max_threads=10, max_queue_size=1000):
        self.log_queue = queue.Queue(maxsize=max_queue_size)
        self.max_threads = max_threads
        self.threads = []
        self.lock = threading.Lock()
        self.stop_event = threading.Event()

    def process_log(self, log_message):
        with self.lock:
            print(f"Processing log: {log_message} (Thread: {threading.current_thread().name})")

    def worker(self):
        while not self.stop_event.is_set():
            try:
                log_message = self.log_queue.get(timeout=1)
                self.process_log(log_message)
                self.log_queue.task_done()
            except queue.Empty:
                continue

    def start(self):
        for _ in range(self.max_threads):
            thread = threading.Thread(target=self.worker)
            thread.daemon = True
            thread.start()
            self.threads.append(thread)

    def stop(self):
        self.stop_event.set()
        for thread in self.threads:
            thread.join()

    def add_log(self, log_message):
        self.log_queue.put(log_message)

def test_log_processor():
    log_processor = LogProcessor(max_threads=10)
    log_processor.start()

    # Simulate adding 1000 log messages
    for i in range(1000):
        log_processor.add_log(f"Log message {i}")

    # Wait for all logs to be processed
    log_processor.log_queue.join()
    log_processor.stop()

if __name__ == "__main__":
    test_log_processor()
