#include <iostream>
#include <vector>
#include <algorithm>

void generateUniquePermutations(std::vector<int>& nums, std::vector<std::vector<int>>& result, int start) {
    if (start == nums.size()) {
        result.push_back(nums);
        return;
    }
    for (int i = start; i < nums.size(); ++i) {
        if (i != start && nums[i] == nums[start]) continue;
        std::swap(nums[start], nums[i]);
        generateUniquePermutations(nums, result, start + 1);
        std::swap(nums[start], nums[i]);
    }
}

std::vector<std::vector<int>> permuteUnique(std::vector<int>& nums) {
    std::vector<std::vector<int>> result;
    std::sort(nums.begin(), nums.end());
    generateUniquePermutations(nums, result, 0);
    if (result.size() > 1500) {
        result.resize(1500);
    }
    return result;
}

int main() {
    std::vector<int> nums;
    int n, num;
    std::cout << "Enter the number of elements: ";
    std::cin >> n;
    std::cout << "Enter the elements: ";
    for (int i = 0; i < n; ++i) {
        std::cin >> num;
        nums.push_back(num);
    }
    std::vector<std::vector<int>> permutations = permuteUnique(nums);
    for (const auto& perm : permutations) {
        for (int num : perm) {
            std::cout << num << " ";
        }
        std::cout << std::endl;
    }
    return 0;
}
